    private static int[] createFilledIntArray(int value) {
        int[] values = new int[MAX_COMBATANTS];
        Arrays.fill(values, value);
        return values;
    }

    private static int[] createVersusTeamArray() {
        int[] teams = new int[MAX_COMBATANTS];
        Arrays.fill(teams, 1);
        if (teams.length > 1) teams[1] = 2;
        if (teams.length > 2) teams[2] = 1;
        if (teams.length > 3) teams[3] = 2;
        return teams;
    }

    private static int[] createPvETeamArray() {
        int[] teams = new int[MAX_COMBATANTS];
        Arrays.fill(teams, 2);
        if (teams.length > 0) teams[0] = 1;
        return teams;
    }

    private static Preferences defaultSavePreferencesRoot() {
        if (shouldUseIsolatedTestPrefs()) {
            return Preferences.userRoot().node("/birdfight3-tests/runtime/" + UUID.randomUUID());
        }
        return Preferences.userNodeForPackage(BirdGame3.class);
    }

    private static boolean shouldUseIsolatedTestPrefs() {
        if (System.getProperty("surefire.test.class.path") != null) {
            return true;
        }
        for (StackTraceElement element : Thread.currentThread().getStackTrace()) {
            String className = element.getClassName();
            if (className.startsWith("org.junit.") || className.startsWith("org.apache.maven.surefire.")) {
                return true;
            }
        }
        return false;
    }

    public BirdGame3() {
        this(defaultSavePreferencesRoot());
    }

